"use client";

import { motion } from "framer-motion";
import { useState } from "react";
import {
  Box,
  Circle,
  Cone,
  Cuboid,
  Cylinder,
  Download,
  Hexagon,
  ImageIcon,
  Rabbit,
  RotateCcw,
  RotateCw,
  Scaling,
  SlidersHorizontal,
  Square,
  Triangle
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useMetricsStore } from "@/lib/stores/metrics-store";

export type GeometryShapeId =
  | "triangle"
  | "quad"
  | "cube"
  | "sphere"
  | "plane"
  | "cylinder"
  | "cone"
  | "torus"
  | "monkey"
  | "bunny";

interface ShapeMeta {
  id: GeometryShapeId;
  name: string;
  icon: typeof Triangle;
  vertices: number;
  triangles: number;
  indices: number;
  description: string;
}

const shapes: ShapeMeta[] = [
  { id: "triangle", name: "Triangle", icon: Triangle, vertices: 3, triangles: 1, indices: 3, description: "The simplest polygon: three vertices and one face." },
  { id: "quad", name: "Quad", icon: Square, vertices: 4, triangles: 2, indices: 6, description: "A four-vertex plane split into two triangles." },
  { id: "cube", name: "Cube", icon: Cuboid, vertices: 24, triangles: 12, indices: 36, description: "Six faces, each a quad made of two triangles." },
  { id: "sphere", name: "Sphere", icon: Circle, vertices: 642, triangles: 1280, indices: 1920, description: "A UV sphere generated with 16 rings and segments." },
  { id: "plane", name: "Plane", icon: Square, vertices: 4, triangles: 2, indices: 6, description: "A flat ground plane useful for shadows and grids." },
  { id: "cylinder", name: "Cylinder", icon: Cylinder, vertices: 132, triangles: 248, indices: 372, description: "A capped cylinder with radial topology." },
  { id: "cone", name: "Cone", icon: Cone, vertices: 66, triangles: 124, indices: 186, description: "A tapered cone with a circular base." },
  { id: "torus", name: "Torus", icon: Hexagon, vertices: 576, triangles: 1152, indices: 1728, description: "A donut shape formed by revolving a circle." },
  { id: "monkey", name: "Monkey", icon: ImageIcon, vertices: 786, triangles: 1492, indices: 2238, description: "Blender Suzanne: a recognizable test head." },
  { id: "bunny", name: "Stanford Bunny", icon: Rabbit, vertices: 34834, triangles: 69451, indices: 104073, description: "Classic scanned model for mesh LOD experiments." }
];

const transformPresets = [
  { id: "rotate", name: "Rotate", icon: RotateCw, type: "transform" as const },
  { id: "translate", name: "Translate", icon: RotateCcw, type: "transform" as const },
  { id: "scale", name: "Scale", icon: Scaling, type: "transform" as const },
  { id: "subdivide", name: "Subdivide", icon: SlidersHorizontal, type: "transform" as const }
];

const viewToggles = [
  { id: "wireframe", name: "Wireframe", icon: Box },
  { id: "normals", name: "Normals", icon: SlidersHorizontal }
];

export function GeometryLabPanel() {
  const [active, setActive] = useState<GeometryShapeId>("triangle");
  const [activeTransform, setActiveTransform] = useState<string | null>(null);
  const [toggles, setToggles] = useState({ wireframe: false, normals: false });
  const [values, setValues] = useState({ x: 0, y: 0, z: 0, scale: 1, subdivisions: 0 });
  const activeShape = shapes.find((s) => s.id === active) ?? shapes[0]!;
  const updateMetrics = useMetricsStore((s) => s.updateMetrics);

  const handleShapeClick = (id: GeometryShapeId) => {
    setActive(id);
    updateMetrics({
      vertices: activeShape.vertices,
      triangles: activeShape.triangles,
      buffers: 2
    });
  };

  const handleExport = () => {
    const payload = JSON.stringify(
      {
        shape: activeShape.id,
        vertices: activeShape.vertices,
        triangles: activeShape.triangles,
        transform: activeTransform,
        viewToggles: toggles,
        values
      },
      null,
      2
    );
    const blob = new Blob([payload], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${activeShape.id}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="flex h-full flex-col overflow-hidden rounded-2xl border border-white/10 bg-[#0B0C15]/80 p-5 shadow-card">
      <div className="mb-4">
        <span className="text-[10px] uppercase tracking-[0.3em] text-brand-subtle">Geometry Lab</span>
        <h2 className="mt-1 font-display text-lg font-semibold text-white">Interactive Geometry</h2>
        <p className="text-xs text-slate-400">Select a shape, apply transforms, and inspect topology.</p>
      </div>

      <div className="mb-3 grid grid-cols-5 gap-2 sm:grid-cols-5">
        {shapes.map((shape) => {
          const Icon = shape.icon;
          const isActive = active === shape.id;
          return (
            <button
              key={shape.id}
              onClick={() => handleShapeClick(shape.id)}
              className={cn(
                "flex flex-col items-center gap-1.5 rounded-xl border p-2 text-[10px] transition-all focus-visible:ring-2 focus-visible:ring-brand/60",
                isActive
                  ? "border-brand/50 bg-brand/15 text-white"
                  : "border-white/10 bg-white/5 text-slate-400 hover:border-white/20 hover:text-slate-200"
              )}
              aria-label={`Select ${shape.name}`}
              title={shape.name}
            >
              <Icon className="size-4" />
              <span className="truncate max-w-full">{shape.name}</span>
            </button>
          );
        })}
      </div>

      <div className="mb-3 flex flex-wrap items-center gap-2">
        {transformPresets.map((t) => {
          const Icon = t.icon;
          const isActive = activeTransform === t.id;
          return (
            <button
              key={t.id}
              onClick={() => setActiveTransform(isActive ? null : t.id)}
              className={cn(
                "flex items-center gap-1.5 rounded-lg border px-2.5 py-1.5 text-[11px] font-medium transition-colors",
                isActive ? "border-brand/40 bg-brand/15 text-brand" : "border-white/10 bg-white/5 text-slate-300 hover:bg-white/10"
              )}
              aria-label={t.name}
              title={t.name}
            >
              <Icon className="size-3.5" />
              {t.name}
            </button>
          );
        })}

        <div className="mx-1 h-4 w-px bg-white/10" />

        {viewToggles.map((t) => {
          const Icon = t.icon;
          const isActive = toggles[t.id as keyof typeof toggles];
          return (
            <button
              key={t.id}
              onClick={() => setToggles((prev) => ({ ...prev, [t.id]: !prev[t.id as keyof typeof prev] }))}
              className={cn(
                "flex items-center gap-1.5 rounded-lg border px-2.5 py-1.5 text-[11px] font-medium transition-colors",
                isActive ? "border-cyan-400/40 bg-cyan-400/15 text-cyan-300" : "border-white/10 bg-white/5 text-slate-300 hover:bg-white/10"
              )}
              aria-label={t.name}
              aria-pressed={isActive}
              title={t.name}
            >
              <Icon className="size-3.5" />
              {t.name}
            </button>
          );
        })}

        <button
          onClick={handleExport}
          className="ml-auto flex items-center gap-1.5 rounded-lg border border-white/10 bg-white/5 px-2.5 py-1.5 text-[11px] font-medium text-slate-300 transition-colors hover:bg-white/10"
          aria-label="Export shape JSON"
          title="Export shape JSON"
        >
          <Download className="size-3.5" />
          Export
        </button>
      </div>

      {activeTransform ? (
        <div className="mb-3 rounded-xl border border-white/10 bg-white/5 p-3">
          <div className="mb-2 text-[10px] uppercase tracking-wider text-brand-subtle">{activeTransform}</div>
          <div className="grid grid-cols-2 gap-2 sm:grid-cols-4">
            {activeTransform === "subdivide" ? (
              <label className="flex flex-col gap-1 text-[10px] text-slate-400">
                Levels
                <input
                  type="range"
                  min={0}
                  max={3}
                  step={1}
                  value={values.subdivisions}
                  onChange={(e) => setValues((v) => ({ ...v, subdivisions: Number(e.target.value) }))}
                  className="accent-brand"
                />
              </label>
            ) : (
              <>
                {activeTransform === "scale" ? (
                  <label className="flex flex-col gap-1 text-[10px] text-slate-400">
                    Scale
                    <input
                      type="range"
                      min={0.5}
                      max={2}
                      step={0.1}
                      value={values.scale}
                      onChange={(e) => setValues((v) => ({ ...v, scale: Number(e.target.value) }))}
                      className="accent-brand"
                    />
                  </label>
                ) : (
                  <>
                    <label className="flex flex-col gap-1 text-[10px] text-slate-400">
                      X
                      <input
                        type="range"
                        min={-1}
                        max={1}
                        step={0.1}
                        value={values.x}
                        onChange={(e) => setValues((v) => ({ ...v, x: Number(e.target.value) }))}
                        className="accent-brand"
                      />
                    </label>
                    <label className="flex flex-col gap-1 text-[10px] text-slate-400">
                      Y
                      <input
                        type="range"
                        min={-1}
                        max={1}
                        step={0.1}
                        value={values.y}
                        onChange={(e) => setValues((v) => ({ ...v, y: Number(e.target.value) }))}
                        className="accent-brand"
                      />
                    </label>
                    <label className="flex flex-col gap-1 text-[10px] text-slate-400">
                      Z
                      <input
                        type="range"
                        min={-1}
                        max={1}
                        step={0.1}
                        value={values.z}
                        onChange={(e) => setValues((v) => ({ ...v, z: Number(e.target.value) }))}
                        className="accent-brand"
                      />
                    </label>
                  </>
                )}
              </>
            )}
          </div>
        </div>
      ) : null}

      <motion.div
        key={active}
        initial={{ opacity: 0, y: 8 }}
        animate={{ opacity: 1, y: 0 }}
        className="flex flex-1 flex-col rounded-xl border border-white/10 bg-slate-950/50 p-4"
      >
        <div className="mb-2 flex items-center justify-between">
          <span className="text-sm font-semibold text-white">{activeShape.name}</span>
          <span className="text-[10px] text-slate-500">{activeShape.id}</span>
        </div>
        <p className="mb-3 text-[11px] leading-relaxed text-slate-400">{activeShape.description}</p>
        <div className="relative flex-1 rounded-lg border border-dashed border-white/10 bg-white/5">
          <div className="absolute left-3 top-3 flex flex-wrap gap-1.5">
            {toggles.wireframe ? (
              <span className="rounded bg-cyan-400/20 px-1.5 py-0.5 text-[9px] text-cyan-300">wireframe</span>
            ) : null}
            {toggles.normals ? (
              <span className="rounded bg-cyan-400/20 px-1.5 py-0.5 text-[9px] text-cyan-300">normals</span>
            ) : null}
          </div>
        </div>
        <div className="mt-3 grid grid-cols-3 gap-2 text-center text-[11px] text-slate-400">
          <div className="rounded-lg bg-white/5 p-2">
            <div className="font-display text-sm text-white">{activeShape.vertices.toLocaleString()}</div>
            <div>Vertices</div>
          </div>
          <div className="rounded-lg bg-white/5 p-2">
            <div className="font-display text-sm text-white">{activeShape.triangles.toLocaleString()}</div>
            <div>Triangles</div>
          </div>
          <div className="rounded-lg bg-white/5 p-2">
            <div className="font-display text-sm text-white">{activeShape.indices.toLocaleString()}</div>
            <div>Indices</div>
          </div>
        </div>
      </motion.div>
    </div>
  );
}
